import { promises as fs } from "fs"
import path from "path"
import { NextResponse } from "next/server"

export const runtime = "nodejs"
export const dynamic = "force-dynamic"

// Reads data/bench/index.json — the flat list of all known (bench_id, run_id)
// pairs with summary fields. Generated by the local-dev pull script today;
// will be generated by Codex's push pipeline later. Schema is the same either way.
async function readBenchIndex() {
  try {
    const raw = await fs.readFile(path.join(process.cwd(), "data/bench/index.json"), "utf-8")
    return JSON.parse(raw)
  } catch {
    return null
  }
}

export async function GET() {
  const index = await readBenchIndex()
  if (!index) {
    return NextResponse.json(
      { error: "No bench index — run scripts/pull-bench-data.py or wait for Codex publication" },
      { status: 404 }
    )
  }
  return NextResponse.json(index)
}
